const extractRawText = (item) =>
  item.json.output?.[0]?.content?.[0]?.text ||
  item.json.output?.[0]?.text ||
  item.json.content?.[0]?.text ||
  item.json.text ||
  item.json.response ||
  item.json.message ||
  '';

const extractJobId = (url) =>
  String(url || '').match(/jobs\/view\/(\d+)/)?.[1] || '';

const locationAllowed = (location, workType = '') => {
  const loc = String(location || '').toLowerCase().trim();
  const wt = String(workType || '').toLowerCase().trim();

  if (/relocation|relocate\s*required/.test(loc)) return false;
  if (loc.includes('bulgaria')) return true;

  if (
    loc.includes('remote europe') ||
    loc.includes('remote emea') ||
    loc.includes('emea · remote') ||
    loc.includes('europe · remote') ||
    loc.includes('remote worldwide') ||
    loc.includes('remote global')
  ) return true;

  const hasRemote = wt === 'remote' || /\bremote\b/.test(loc);
  const hasHybrid = wt === 'hybrid' || /\bhybrid\b/.test(loc);
  const hasOnsite =
    wt === 'onsite' ||
    wt === 'on-site' ||
    /\bon-?site\b/.test(loc) ||
    /\bonsite\b/.test(loc);

  if (hasRemote && loc.includes('· remote')) return true;
  if (hasRemote && !hasHybrid && !hasOnsite) return true;
  if (hasHybrid && !loc.includes('bulgaria')) return false;
  if (hasOnsite && !loc.includes('bulgaria')) return false;

  if (!hasRemote && !loc.includes('bulgaria')) {
    const nonRemoteCountries = [
      'united kingdom', 'netherlands', 'spain', 'france', 'italy',
      'germany', 'portugal', 'switzerland', 'united states',
    ];
    if (nonRemoteCountries.some((c) => loc.includes(c))) return false;
  }

  return true;
};

const locationRejectReason = (location, workType, allowed) => {
  if (allowed) return '';

  const loc = String(location || '').toLowerCase().trim();
  const wt = String(workType || '').toLowerCase().trim();

  if (/relocation|relocate\s*required/.test(loc)) return 'Relocation required.';

  if ((/\bhybrid\b/.test(loc) || wt === 'hybrid') && !loc.includes('bulgaria')) {
    return 'Hybrid outside Bulgaria rejected.';
  }

  if ((/\bon-?site\b/.test(loc) || /\bonsite\b/.test(loc) || wt === 'onsite') && !loc.includes('bulgaria')) {
    return 'On-site outside Bulgaria rejected.';
  }

  return 'Non-remote location outside Bulgaria rejected.';
};

const looksFakeCompany = (company, role) => {
  const c = String(company || '').toLowerCase().trim();
  const r = String(role || '').toLowerCase().trim();

  if (!c) return true;
  if (c === r) return true;

  const blockedExactCompanies = [
    'remote',
    'hybrid',
    'onsite',
    'on-site',
    'on site',
    'full-time',
    'part-time',
    'contract',
    'temporary',
    'internship'
  ];

  if (blockedExactCompanies.includes(c)) return true;

  if (
    c.includes('connections') ||
    c.includes('install linkedin widgets') ||
    c.includes('see all jobs') ||
    c.includes('actively recruiting') ||
    c.includes('actively reviewing applicants') ||
    c.includes('fast growing') ||
    c.includes('promoted by hirer') ||
    c.includes('responses managed off linkedin')
  ) return true;

  const roleWords = [
    'manager', 'director', 'head', 'chief', 'vp',
    'operations', 'revenue', 'strategy', 'business',
    'lead', 'program', 'product', 'commercial', 'revops'
  ];

  return roleWords.some(w => c.includes(w));
};

const inferWorkType = (text) => {
  const t = String(text || '').toLowerCase();
  if (/\bremote\b/.test(t)) return 'Remote';
  if (/\bhybrid\b/.test(t)) return 'Hybrid';
  if (/\b(on-?site|on site)\b/.test(t)) return 'Onsite';
  return '';
};

const parseLocationFromText = (text) => {
  const t = String(text || '');
  const lower = t.toLowerCase();
  const workType = inferWorkType(t);

  if (/remote europe/.test(lower)) return 'Remote Europe';
  if (/remote emea/.test(lower)) return 'Remote EMEA';
  if (/remote worldwide|remote global/.test(lower)) return 'Remote Worldwide';

  const countries = [
    ['bulgaria', 'Bulgaria'],
    ['united kingdom', 'United Kingdom'],
    ['portugal', 'Portugal'],
    ['italy', 'Italy'],
    ['france', 'France'],
    ['switzerland', 'Switzerland'],
    ['netherlands', 'Netherlands'],
    ['germany', 'Germany'],
    ['spain', 'Spain'],
    ['united states', 'United States'],
  ];

  for (const [needle, label] of countries) {
    if (lower.includes(needle)) {
      return workType ? `${label} · ${workType}` : label;
    }
  }

  return 'Not specified';
};

const buildDeterministicJobs = (content) => {
  const hints = content.JobUrlHints || [];
  const subjectHint = content.SubjectJobHint || {};
  const jobs = [];

  const skipLine = (line, role) =>
    !line ||
    line === role ||
    /^(apply|save|easy apply|full-time|part-time|promoted|similar jobs|view job|see all jobs)$/i.test(line) ||
    /^(remote|hybrid|on-?site|on site)$/i.test(line) ||
    /^\d+ (connection|mutual)/i.test(line);

  for (const hint of hints) {
    const url = String(hint.url || '').trim();
    if (!url) continue;

    const role = String(hint.anchorText || subjectHint.role || '').trim();
    const contextLines = String(hint.context || '')
      .split('\n')
      .map((l) => l.trim())
      .filter(Boolean);

    let company = '';

    if (hints.length === 1 && subjectHint.company) {
      company = String(subjectHint.company).trim();
    }

    if (!company) {
      company = contextLines.find((l) => !skipLine(l, role) && l.length <= 80) || '';
    }

    if (!company || !role) continue;

    jobs.push({
      company,
      role,
      location: parseLocationFromText(hint.context),
      work_type: inferWorkType(hint.context),
      url,
    });
  }

  if (jobs.length === 0 && hints.length === 1 && subjectHint.company && subjectHint.role) {
    jobs.push({
      company: String(subjectHint.company).trim(),
      role: String(subjectHint.role).trim(),
      location: parseLocationFromText(content.EmailText || ''),
      work_type: inferWorkType(content.EmailText || ''),
      url: String(hints[0].url || '').trim(),
    });
  }

  return jobs;
};

const normalizeEmailItems = $('Normalize Email Content').all();

const getEmailFields = (index) => {
  const emailMeta = normalizeEmailItems[index]?.json || {};

  return {
    EmailId: emailMeta.EmailId || '',
    ThreadId: emailMeta.ThreadId || '',
    EmailReceived: emailMeta.EmailReceived || '',
    EmailSubject: emailMeta.EmailSubject || '',
    EmailSnippet: emailMeta.EmailSnippet || '',
  };
};

const buildFallbackItem = (emailFields, extractionError = 'AI Extract returned []') => ({
  json: {
    ...emailFields,
    Source: 'LinkedIn Email',
    Status: 'Rejected',
    Apply: 'NO',
    Recommendation: 'NO',
    Reason: 'AI Extract returned no job cards',
    RejectReason: 'AI Extract returned no job cards',
    MainRisk: 'No job card parsed from email',
    Risk: 'No job card parsed from email',
    Role: '',
    Company: '',
    Location: '',
    URL: '',
    JobUrl: '',
    JobId: '',
    WorkType: '',
    DedupeKey: emailFields.EmailId || '',
    ExtractionStatus: 'NO_JOB_CARD',
    ExtractionError: extractionError,
    PipelineStage: 'NO_JOB_CARD',
    LocationAllowed: true,
    LocationRejectReason: 'AI Extract returned no job cards',
    Notes: '',
    ParseError: '',
  },
});

const output = [];
const seen = new Set();
const inputItems = $input.all();

for (let inputIndex = 0; inputIndex < inputItems.length; inputIndex++) {
  const item = inputItems[inputIndex];
  const emailFields = getEmailFields(inputIndex);
  const raw = extractRawText(item);

  let clean = String(raw)
    .replace(/```json/gi, '')
    .replace(/```/g, '')
    .trim();

  const firstBracket = clean.indexOf('[');
  const lastBracket = clean.lastIndexOf(']');

  if (firstBracket !== -1 && lastBracket !== -1 && lastBracket > firstBracket) {
    clean = clean.slice(firstBracket, lastBracket + 1);
  }

  let parsed;

  try {
    parsed = JSON.parse(clean);
  } catch (e) {
    output.push(buildFallbackItem(emailFields, 'AI Extract returned invalid JSON'));
    continue;
  }

  const jobs = Array.isArray(parsed) ? parsed : (parsed.jobs || []);

  let jobList = jobs;

  if (jobList.length === 0) {
    const content = normalizeEmailItems[inputIndex]?.json || {};
    jobList = buildDeterministicJobs(content);

    if (jobList.length === 0) {
      output.push(buildFallbackItem(emailFields));
      continue;
    }
  }

  for (const j of jobList) {
    if (!j || !j.company || !j.role) continue;
    if (looksFakeCompany(j.company, j.role)) continue;

    const company = String(j.company || '').trim();
    const role = String(j.role || '').trim();
    const location = String(j.location || 'Not specified').trim();
    const workType = String(j.work_type || '').trim();
    const url = String(j.url || '').trim();
    const jobId = extractJobId(url);
    const dedupeKey = (jobId || `${company}|${role}|${location}`).toLowerCase();

    if (!dedupeKey || dedupeKey === '||') continue;
    if (seen.has(dedupeKey)) continue;

    seen.add(dedupeKey);

    const allowed = locationAllowed(location, workType);

    output.push({
      json: {
        ...emailFields,
        Role: role,
        Company: company,
        JobId: jobId,
        Location: location,
        WorkType: workType,
        URL: url,
        LocationAllowed: allowed,
        LocationRejectReason: locationRejectReason(location, workType, allowed),
        Source: 'LinkedIn',
        Status: 'New',
        Notes: '',
        ParseError: '',
        DedupeKey: dedupeKey
      }
    });
  }
}

return output;

// DEV-ONLY: set to true to inject a low-fit mock job and bypass Gmail parse output.
// Must remain false for normal DEV/production runs.
const DEV_TEST_MODE_ENABLED = false;

if (!DEV_TEST_MODE_ENABLED) {
  return $input.all();
}

return [
  {
    json: {
      EmailId: 'test-low-fit-email',
      ThreadId: 'test-low-fit-thread',
      EmailReceived: String(Date.now()),
      EmailSubject: 'TEST low fit job',
      EmailSnippet: 'Entry-level customer support role in the United States, on-site.',
      Role: 'Junior Customer Support Agent',
      Company: 'Test Company',
      Location: 'United States · On-site',
      URL: 'https://example.com/test-job',
      JobUrl: 'https://example.com/test-job',
      JobId: '',
      WorkType: 'Onsite',
      Source: 'TEST',
      Status: 'New',
      Notes: '',
      ParseError: '',
      DedupeKey: 'test-low-fit-job',
      LocationAllowed: false,
      LocationRejectReason: 'Country-specific or non-Bulgaria location rejected.',
      DevTestMode: true,
      DevTestCase: 'LOW_PREVIEW_SCORE',
    },
  },
];

const url = String($json.URL || '').trim();

return {
  json: {
    ...$json,
    HardReject: false,
    RejectReason: '',
    NeedsEnrichment: url.includes('/jobs/view/'),
    PolicyVersion: '1.1',
    PipelineStage: $json.ExtractionStatus === 'NO_JOB_CARD' ? 'NO_JOB_CARD' : ($json.HardReject === true ? 'POLICY_REJECT' : ''),
  },
};

// Preview gate threshold — change PreviewScoreThreshold here only (default 7).
// PREVIEW STAGE FIELDS (email card only): PreviewScore, PreviewRecommendation, PreviewReason, PreviewRisk, PreviewCV
// Do not write Score or VerifiedScore here.
const PreviewScoreThreshold = 7;

const base = $('Policy Engine').item?.json || {};

const allowedCvs = [
  'COO CV',
  'GTM & Commercial Operations CV',
  'Strategy & Operations CV',
  'AI Transformation CV',
  'Project / Program Leadership CV',
];

const normalizeCv = (cv) => {
  const value = String(cv || '').trim();
  return allowedCvs.includes(value) ? value : 'Strategy & Operations CV';
};

const clampScore = (score) => {
  const n = Number(score);
  if (!Number.isFinite(n)) return 0;
  return Math.max(0, Math.min(10, Math.round(n)));
};

const looksLikeLocationDecision = (text) => {
  const t = String(text || '').toLowerCase();
  if (!t.trim()) return false;
  return (
    /remote not acceptable|not acceptable for|country-specific remote|country specific remote|work authorization|residents only|uk remote|united kingdom remote|spain remote|netherlands remote|france remote|italy remote|bulgaria allowed|non-bulgaria|location reject|relocation required|outside bulgaria/.test(t) &&
    !/role|seniority|function|company|executive|coo|operations|transformation|junior|support/.test(t)
  );
};

const sanitizePreviewText = (text, fallback) => {
  const value = String(text || '').trim();
  if (!value) return fallback;
  return looksLikeLocationDecision(value) ? fallback : value;
};

const skipPreview =
  base.ExtractionStatus === 'NO_JOB_CARD' ||
  (!String(base.Role || '').trim() && !String(base.Company || '').trim());

if (skipPreview) {
  return {
    json: {
      ...base,
      PreviewScore: 0,
      PreviewRecommendation: 'NO',
      PreviewReason: base.ExtractionError || base.RejectReason || 'No job card parsed from email',
      PreviewRisk: base.MainRisk || 'No job card parsed from email',
      PreviewCV: 'Strategy & Operations CV',
      PreviewScoreThreshold,
      PreviewPassesThreshold: false,
      PipelineStage: 'NO_JOB_CARD',
    },
  };
}

const raw =
  $json.output?.[0]?.content?.[0]?.text ||
  $json.output?.[0]?.text ||
  $json.content?.[0]?.text ||
  $json.text ||
  '';

const clean = String(raw)
  .replace(/```json/gi, '')
  .replace(/```/g, '')
  .trim();

let ai = {};

try {
  ai = JSON.parse(clean);
} catch (e) {
  ai = {};
}

const previewScore = clampScore(ai.preview_score);
const previewPassesThreshold = previewScore >= PreviewScoreThreshold;

const normalizePreviewRecommendation = (rec, score, threshold) => {
  let value = String(rec || '').trim().toUpperCase();
  if (!['YES', 'MONITOR', 'NO'].includes(value)) {
    if (score >= threshold) value = 'YES';
    else if (score >= 5) value = 'MONITOR';
    else value = 'NO';
  }
  if (value === 'YES' && score < threshold) value = 'MONITOR';
  return value;
};

const previewRecommendation = normalizePreviewRecommendation(
  ai.preview_recommendation,
  previewScore,
  PreviewScoreThreshold,
);

const previewReason = sanitizePreviewText(
  ai.preview_reason,
  'Card-level role/seniority fit assessed; location eligibility deferred to full job read.',
);
const previewRisk = sanitizePreviewText(
  ai.preview_risk,
  'Location eligibility unknown from email card; verify after full LinkedIn posting read.',
);

return {
  json: {
    ...base,
    PreviewScore: previewScore,
    PreviewRecommendation: previewRecommendation,
    PreviewReason: previewReason,
    PreviewRisk: previewRisk,
    PreviewCV: normalizeCv(ai.preview_cv),
    PreviewScoreThreshold,
    PreviewPassesThreshold: previewPassesThreshold,
  },
};

// Preview reject — keep Preview* intact; Verified* empty; Score mapped at Sheets only.
// Runs ONLY on Check Preview Threshold FALSE branch (PreviewPassesThreshold === false).
return {
  json: {
    ...$json,
    Status: 'Rejected',
    RejectReason: 'Preview score below threshold',
    FinalDecision: 'REJECT_PREVIEW',
    PipelineStage: $json.ExtractionStatus === 'NO_JOB_CARD' ? 'NO_JOB_CARD' : 'PREVIEW_REJECT',
    VerifiedScore: '',
    VerifiedRecommendation: '',
    VerifiedRisk: '',
    VerifiedWhyApply: '',
    FinalCV: '',
    VerifiedInterviewProbability: '',
    VerifiedPriority: '',
    SalaryEstimate: '',
    SalaryTarget: '',
    SalaryConfidence: '',
    SalaryAssumption: '',
    LocationFit: '',
  },
};

const config = $input.first().json;
const LINKEDIN_LABEL_ID = 'Label_3053362597517296520';

const asBool = (v) => v === true || v === 'true' || v === 1;
const asString = (v) => (v === undefined || v === null ? '' : String(v).trim());

if (!asBool(config.TestMode)) {
  return [
    {
      json: {
        fetchMode: 'production',
        labelIds: [LINKEDIN_LABEL_ID],
        limit: 1,
      },
    },
  ];
}

const testEmailId = asString(config.TestEmailId);
const testThreadId = asString(config.TestThreadId);
const testMax = Math.max(1, Number(config.TestMaxResults) || 1);
const subjectContains = asString(config.TestSubjectContains);
const receivedAfter = asString(config.TestReceivedAfter);
const receivedBefore = asString(config.TestReceivedBefore);

if (testEmailId) {
  return [
    {
      json: {
        fetchMode: 'byEmailId',
        messageId: testEmailId,
        limit: 1,
      },
    },
  ];
}

const qParts = [];
if (testThreadId) qParts.push(`threadId:${testThreadId}`);
if (subjectContains) qParts.push(`subject:"${subjectContains.replace(/"/g, '')}"`);

return [
  {
    json: {
      fetchMode: 'search',
      labelIds: [LINKEDIN_LABEL_ID],
      limit: testMax,
      q: qParts.join(' ').trim(),
      receivedAfter,
      receivedBefore,
    },
  },
];

const getHeader = (json, name) => {
  const headers = json.payload?.headers || json.headers || [];
  if (Array.isArray(headers)) {
    const hit = headers.find(
      (h) => String(h.name || h.key || '').toLowerCase() === name.toLowerCase(),
    );
    return hit?.value || hit?.headerValue || '';
  }
  if (headers && typeof headers === 'object') {
    return headers[name] || headers[name.toLowerCase()] || '';
  }
  return '';
};

const stripHtmlPreview = (html, maxLen = 300) => {
  const text = String(html || '')
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
  return text.slice(0, maxLen);
};

const firstNonEmpty = (...values) => {
  for (const value of values) {
    if (value !== undefined && value !== null && String(value).trim() !== '') {
      return String(value).trim();
    }
  }
  return '';
};

const resolveEmailReceived = (json) =>
  firstNonEmpty(
    json.internalDate,
    json.date,
    json.receivedDate,
    getHeader(json, 'Date'),
  );

const resolveEmailSnippet = (json) => {
  const preview = firstNonEmpty(
    json.snippet,
    json.textPlain,
    stripHtmlPreview(json.textHtml || json.html || json.textAsHtml),
    stripHtmlPreview(json.text || json.body),
  );
  return preview.length > 300 ? preview.slice(0, 300) : preview;
};

return {
  json: {
    ...$json,
    EmailId: $json.id || '',
    ThreadId: $json.threadId || '',
    EmailReceived: resolveEmailReceived($json),
    EmailSubject: $json.Subject || $json.subject || '',
    EmailSnippet: resolveEmailSnippet($json),
  },
};

const decodeHtml = (s) =>
  (s || '')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'");

const getHeader = (json, name) => {
  const headers = json.payload?.headers || json.headers || [];
  if (Array.isArray(headers)) {
    const hit = headers.find(
      (h) => String(h.name || h.key || '').toLowerCase() === name.toLowerCase(),
    );
    return hit?.value || hit?.headerValue || '';
  }
  if (headers && typeof headers === 'object') {
    return headers[name] || headers[name.toLowerCase()] || '';
  }
  return '';
};

const stripHtmlPreview = (html, maxLen = 300) => {
  const text = String(html || '')
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
  return text.slice(0, maxLen);
};

const firstNonEmpty = (...values) => {
  for (const value of values) {
    if (value !== undefined && value !== null && String(value).trim() !== '') {
      return String(value).trim();
    }
  }
  return '';
};

const resolveEmailReceived = (json) =>
  firstNonEmpty(
    json.internalDate,
    json.date,
    json.receivedDate,
    getHeader(json, 'Date'),
  );

const resolveEmailSnippet = (json) => {
  const preview = firstNonEmpty(
    json.snippet,
    json.textPlain,
    stripHtmlPreview(json.textHtml || json.html || json.textAsHtml),
    stripHtmlPreview(json.text || json.body),
  );
  return preview.length > 300 ? preview.slice(0, 300) : preview;
};

const normalizeJobUrl = (raw) => {
  const decoded = decodeHtml(String(raw || '')).trim();
  const jobId = decoded.match(/linkedin\.com(?:\/comm)?\/jobs\/view\/(\d+)/i)?.[1];
  return jobId ? `https://www.linkedin.com/jobs/view/${jobId}` : '';
};

const cleanText = (html) =>
  decodeHtml(html)
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<!--[\s\S]*?-->/g, ' ')
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<\/p>/gi, '\n')
    .replace(/<\/div>/gi, '\n')
    .replace(/<\/li>/gi, '\n')
    .replace(/<\/tr>/gi, '\n')
    .replace(/<\/td>/gi, '\n')
    .replace(/<\/h[1-6]>/gi, '\n')
    .replace(/<[^>]+>/g, ' ')
    .replace(/\n+/g, '\n')
    .replace(/[ \t]+/g, ' ')
    .split('\n')
    .map(x => x.trim())
    .filter(Boolean)
    .join('\n')
    .trim();

const extractLinkedInJobUrls = (html) => {
  const matches =
    String(html || '').match(
      /https?:\/\/(?:[a-z0-9-]+\.)*linkedin\.com(?:\/comm)?\/jobs\/view\/\d+[^"'<\s]*/gi,
    ) || [];
  const seen = new Set();

  return matches
    .map((u) => normalizeJobUrl(u))
    .filter((u) => {
      const id = u.match(/jobs\/view\/(\d+)/)?.[1] || '';
      if (!id || seen.has(id)) return false;
      seen.add(id);
      return true;
    });
};

const parseSubjectJobHint = (subject) => {
  const s = decodeHtml(String(subject || '')).trim();
  if (!s) return { company: '', role: '' };

  const tail = s.includes(':') ? s.split(':').pop().trim() : s;
  const posted = tail.match(/^(.+?)\s+-\s+(.+?)\s+posted\s+on\b/i);
  if (posted) {
    return { company: posted[1].trim(), role: posted[2].trim() };
  }

  const dashed = tail.match(/^([^-]+?)\s+-\s+(.+)$/);
  if (dashed) {
    const company = dashed[1].trim();
    const role = dashed[2].trim();
    if (company && role && !/\bor\b/i.test(role) && role.length < 120) {
      return { company, role };
    }
  }

  return { company: '', role: '' };
};

const extractAnchorJobHints = (html) => {
  const hints = [];
  const seen = new Set();
  const re = /<a[^>]+href=["']([^"']*)["'][^>]*>([\s\S]*?)<\/a>/gi;
  let match;

  while ((match = re.exec(String(html || ''))) !== null) {
    const url = normalizeJobUrl(match[1]);
    if (!url) continue;

    const jobId = url.match(/jobs\/view\/(\d+)/)?.[1] || '';
    if (!jobId || seen.has(jobId)) continue;
    seen.add(jobId);

    hints.push({
      url,
      jobId,
      anchorText: cleanText(match[2]),
      context: cleanText(String(html || '').slice(match.index, match.index + 1200)).slice(0, 500),
    });
  }

  return hints;
};

const formatJobHintsForAI = (hints, subjectHint) => {
  const lines = [];
  if (subjectHint.company || subjectHint.role) {
    lines.push(`Subject hint: company="${subjectHint.company}" role="${subjectHint.role}"`);
  }
  hints.forEach((h, i) => {
    lines.push(`Job block ${i + 1}:`);
    lines.push(`  URL: ${h.url}`);
