const normalizeDetectedCountry = (value) => {
  const v = String(value || '').trim().toLowerCase();
  if (!v) return '';
  if (v === 'uk' || v === 'u.k.' || v.includes('united kingdom') || v.includes('great britain') || v === 'england') {
    return 'United Kingdom';
  }
  if (v.includes('united states') || v === 'usa' || v === 'u.s.' || v === 'u.s.a.') return 'United States';
  return v.replace(/\b\w/g, (c) => c.toUpperCase());
};

const isBulgariaCountry = (country) => /\bbulgaria\b/i.test(String(country || ''));

const getContextWindow = (text, matchIndex, before = 70, after = 90) =>
  text.slice(Math.max(0, matchIndex - before), Math.min(text.length, matchIndex + after));

const isOptionalContext = (text, matchIndex) =>
  OPTIONAL_CONTEXT_PATTERN.test(getContextWindow(text, matchIndex).toLowerCase());

const isMandatoryContext = (text, matchIndex) => {
  const context = getContextWindow(text, matchIndex).toLowerCase();
  if (OPTIONAL_CONTEXT_PATTERN.test(context)) return false;
  return MANDATORY_CONTEXT_PATTERN.test(context);
};

const extractForeignLanguages = (text) => {
  const langs = [];
  const re = new RegExp(FOREIGN_LANGUAGE_PATTERN.source, 'gi');
  let match;
  while ((match = re.exec(String(text || ''))) !== null) {
    langs.push(match[0].trim());
  }
  return [...new Set(langs.map((lang) => lang.toLowerCase()))];
};

const hasMandatoryLanguageContext = (context) => {
  const c = String(context || '').toLowerCase();
  if (!MANDATORY_LANGUAGE_CONTEXT_PATTERN.test(c)) return false;
  if (OPTIONAL_CONTEXT_PATTERN.test(c)) {
    return /\b(?:required|mandatory|essential|must speak|must be fluent|professional fluency|business fluency|native|near-native|c1|c2|excellent command of|proficiency in|fluency in|fluent in|fluent)\b/i.test(c);
  }
  return true;
};

const firstRegexHit = (text, patterns, validate) => {
  for (const pattern of patterns) {
    const re = pattern.re || pattern;
    const flags = re.flags.includes('g') ? re.flags : `${re.flags}g`;
    const globalRe = new RegExp(re.source, flags);
    let match;
    while ((match = globalRe.exec(text)) !== null) {
      if (validate && !validate(text, match)) continue;
      return {
        evidence: match[0].trim(),
        index: match.index,
      };
    }
  }
  return null;
};

const detectMandatoryForeignLanguage = (text) => {
  const source = String(text || '');
  if (source.length < 20) return { hit: false };

  const langRe = new RegExp(FOREIGN_LANGUAGE_PATTERN.source, 'gi');
  let match;
  while ((match = langRe.exec(source)) !== null) {
    const context = getContextWindow(source, match.index, 120, 120);
    if (!hasMandatoryLanguageContext(context)) continue;

    const foreignLangs = extractForeignLanguages(context);
    if (!foreignLangs.length) continue;

    return {
      hit: true,
      category: 'Mandatory foreign language',
      evidence: context.trim().slice(0, 220),
      reason: `Posting requires non-English/Bulgarian language proficiency (${foreignLangs.join(', ')}).`,
    };
  }

  return { hit: false };
};

const detectMandatoryLocalMarket = (text) => {
  const patterns = [
    { re: /\b(?:strong|established|deep|extensive)\s+.{0,50}(?:network|profile|customer base|market knowledge)\b/gi },
    { re: /\blocal market knowledge required\b/gi },
    { re: /\bexisting (?:network|relationships) in\b.{0,50}\b(?:romania|france|germany|uk|united kingdom|benelux|netherlands|spain|italy)\b/gi },
    { re: /\bexisting relationships with\b.{0,80}\b(?:regulators|customers|partners|clients)\b/gi },
    { re: /\b(?:strong|deep|established)\s+(?:uk|united kingdom|german|germany|france|benelux|romanian|romania|netherlands|dutch|spain|spanish|italian|italy)\b.{0,60}(?:network|profile|customer base|market)\b/gi },
    { re: /\b(?:uk|united kingdom)\s+software industry profile\b/gi },
    { re: /\bselling (?:enterprise software )?into\b.{0,50}\b(?:france|benelux|uk|united kingdom|romania|germany|netherlands|spain|italy)\b/gi },
    { re: /\b(?:france|benelux|uk|united kingdom|romania|germany|netherlands)(?:\s+and\/or\s+(?:france|benelux|netherlands|uk|united kingdom))?\s+market experience\b/gi },
    { re: /\b\d+\+?\s*years?\s+(?:of\s+)?(?:experience\s+)?selling\b.{0,80}\b(?:france|benelux|uk|united kingdom|romania|germany|netherlands)\b/gi },
    { re: /\b(?:france|benelux|uk|united kingdom|romania|germany|netherlands)\b.{0,40}\b(?:enterprise sales|market experience|selling into)\b/gi },
    { re: /\b(?:renewable[- ]energy|software industry|enterprise sales|manufacturing)\s+.{0,30}(?:network|profile|customer base)\b/gi },
  ];

  for (const { re } of patterns) {
    const hit = firstRegexHit(text, [re], (source, match) => {
      if (isOptionalContext(source, match.index)) return false;
      const context = getContextWindow(source, match.index).toLowerCase();
      if (/\bbulgaria\b/.test(context) && !/\b(outside|beyond)\s+bulgaria\b/.test(context)) return false;
      return true;
    });
    if (hit) {
      return {
        hit: true,
        category: 'Mandatory local market / network',
        evidence: hit.evidence,
        reason: 'Posting requires deep local market or network knowledge outside Bulgaria.',
      };
    }
  }

  return { hit: false };
};

const detectMandatorySpecializedDomain = (text) => {
  const matched = [];
  for (const term of HARD_FIT_DOMAIN_TERMS) {
    const flags = term.re.flags.includes('g') ? term.re.flags : `${term.re.flags}g`;
    const globalRe = new RegExp(term.re.source, flags);
    let match;
    while ((match = globalRe.exec(text)) !== null) {
      if (isOptionalContext(text, match.index)) continue;
      matched.push({ term, evidence: match[0].trim(), index: match.index });
    }
  }

  if (!matched.length) return { hit: false };

  const mandatoryMatches = matched.filter((item) => isMandatoryContext(text, item.index));
  const hit = mandatoryMatches[0] || (matched.length >= 2 ? matched[0] : null);
  if (!hit) return { hit: false };

  return {
    hit: true,
    category: 'Mandatory specialized industry/domain experience',
    evidence: matched.map((item) => item.evidence).join('; '),
    reason: `Posting makes ${hit.term.label} experience mandatory.`,
  };
};

const detectExcessiveTravel = (text) => {
  const patterns = [
    /\b(?:50|60|70|80|90)\s*%\s*\+?\s*travel\b/gi,
    /\b(?:50|60|70|80)\+?\s*percent\s+travel\b/gi,
    /\bextensive travel required\b/gi,
    /\bfrequent international travel\b/gi,
    /\bweekly travel\b/gi,
    /\btravel most weeks\b/gi,
    /\bsignificant travel\b/gi,
  ];

  const hit = firstRegexHit(text, patterns, (source, match) => !isOptionalContext(source, match.index));
  if (hit) {
    return {
      hit: true,
      category: 'Excessive travel',
      evidence: hit.evidence,
      reason: 'Posting requires heavy or frequent travel.',
    };
  }

  return { hit: false };
};

const detectSpecializedTechnicalProfile = (text) => {
  const matched = [];
  for (const term of HARD_FIT_TECH_TERMS) {
    if (!term.re.test(text)) continue;
    const flags = term.re.flags.includes('g') ? term.re.flags : `${term.re.flags}g`;
    const globalRe = new RegExp(term.re.source, flags);
    const match = globalRe.exec(text);
    if (!match) continue;
    if (isOptionalContext(text, match.index)) continue;
    matched.push(term);
  }

  const specializedCount = matched.filter((term) => term.specialized).length;
  const hasManufacturingTransformation = matched.some((term) => term.label === 'manufacturing transformation');
  const hasErp = matched.some((term) => term.label === 'ERP');
  const totalCount = matched.length;

  const heavyTravel = /\b(?:significant|extensive|frequent|weekly|\b(?:50|60|70|80)\s*%)\s*.{0,20}travel\b/i.test(text)
    || /\btravel\b/i.test(text) && /\b(?:significant|extensive|frequent|weekly)\b/i.test(text);

  const reject =
    specializedCount >= 3
    || (specializedCount >= 2 && hasManufacturingTransformation)
    || (totalCount >= 4 && hasErp && hasManufacturingTransformation)
    || (specializedCount >= 2 && heavyTravel && hasManufacturingTransformation);

  if (!reject) return { hit: false };

  return {
    hit: true,
    category: 'Highly specialized technical/manufacturing requirement',
    evidence: matched.map((term) => term.label).join(', '),
    reason: 'Posting requires a specialized technology/manufacturing transformation leader profile outside core executive scope.',
  };
};

const detectHardFitDisqualifier = (fullJobText, ai) => {
  const text = String(fullJobText || '').trim();
  if (text.length < 20) return { hit: false };

  const detectors = [
    detectMandatoryForeignLanguage,
    detectMandatoryLocalMarket,
    detectMandatorySpecializedDomain,
    detectExcessiveTravel,
    detectSpecializedTechnicalProfile,
  ];

  for (const detect of detectors) {
    const result = detect(text, ai);
    if (result.hit) return result;
  }

  return { hit: false, category: '', evidence: '', reason: '' };
};

const applyHardFitGuard = (ai, fullJobText) => {
  const guard = detectHardFitDisqualifier(fullJobText, ai);
  if (!guard.hit) return { ai, guard: { hit: false } };

  const out = { ...ai };
  out.apply = 'NO';
  out.final_decision = 'REJECT';
  out.biggest_risk = `Hard fit mismatch: ${guard.reason} Evidence: ${guard.evidence}`;
  out.follow_up_priority = 'LOW';

  const score = Number(out.final_score);
  if (Number.isFinite(score) && score > 5) out.final_score = 5;

  return { ai: out, guard };
};

const detectPlgSpecializationCore = (fullJobText, ai) => {
  const text = String(fullJobText || '');
  const roleText = `${ai?.role || ''} ${ai?.company || ''}`.toLowerCase();
  if (text.length < 20) return { central: false };

  const coreHits = PLG_CORE_SIGNALS.filter((signal) => signal.re.test(text) || signal.re.test(roleText));
  const supportHits = PLG_SUPPORT_SIGNALS.filter((signal) => signal.re.test(text));

  const plgTitle =
    /\b(?:head of growth|vp growth|director of growth|chief growth officer|cgo|growth executive|product growth|plg)\b/i.test(roleText)
    || /\bproduct[- ]led growth\b/i.test(roleText);

  const genericExecutiveRole = EXECUTIVE_OPS_ROLE_PATTERN.test(roleText) || EXECUTIVE_OPS_ROLE_PATTERN.test(text.slice(0, 400));

  const central =
    (coreHits.length > 0 && supportHits.length >= 2)
    || (plgTitle && supportHits.length >= 3)
    || (coreHits.length > 0 && plgTitle)
    || (supportHits.length >= 5 && /\b(?:growth|self-serve|product adoption|lifecycle)\b/i.test(text));

  if (!central || (genericExecutiveRole && coreHits.length === 0 && !plgTitle)) {
    return { central: false };
  }

  return {
    central: true,
    evidence: [...coreHits, ...supportHits].map((item) => item.label).slice(0, 8).join(', '),
  };
};

const applyPlgSpecializationCalibration = (ai, fullJobText) => {
  const detection = detectPlgSpecializationCore(fullJobText, ai);
  if (!detection.central) return { ai, calibration: { applied: false } };

  const out = { ...ai };
  const score = Number(out.final_score);
  if (Number.isFinite(score) && score > 6) out.final_score = 6;

  if (String(out.apply || '').toUpperCase() === 'YES') out.apply = 'MONITOR';
  const decision = String(out.final_decision || '').toUpperCase();
  if (decision === 'APPLY NOW' || decision === 'APPLY') {
    out.final_decision = Number(out.final_score) <= 4 ? 'REJECT' : 'MONITOR';
  }

  const plgRisk =
    'Role is primarily a PLG/product-growth specialization outside Ruzha\'s strongest COO / operations transformation profile.';
  const existingRisk = String(out.biggest_risk || '').trim();
  out.biggest_risk = /plg|product-growth|product-led growth/i.test(existingRisk)
    ? existingRisk
    : (existingRisk ? `${plgRisk} ${existingRisk}` : plgRisk);

  return { ai: out, calibration: { applied: true, ...detection } };
};

const isFalsePositiveRestrictionContext = (text, matchIndex) => {
  const windowStart = Math.max(0, matchIndex - 100);
  const context = text.slice(windowStart, matchIndex + 80).toLowerCase();
  return (
    /remote role with travel/.test(context) ||
    /(?:customers?|clients?|users?|markets?|accounts?)\s+(?:in|across|throughout|within)\b/.test(context) ||
    /(?:customer|client|market)\s+focus\b/.test(context) ||
    /(?:company|firm|organization|organisation)\s+headquartered\s+in\b/.test(context) ||
    /\bheadquartered\s+in\b/.test(context) ||
    /global team based in\b/.test(context) ||
    /(?:our|the)\s+team based in\b/.test(context) ||
    /(?:office|offices|hub|hubs)\s+(?:in|across)\b/.test(context)
  );
};

const findCountryInText = (text) => {
  const match = text.match(new RegExp(`\\b(${COUNTRY_NAMES})\\b`, 'i'));
  return match ? normalizeDetectedCountry(match[1]) : '';
};

const detectExplicitFullJobTextLocationRestriction = (fullJobText) => {
  const text = String(fullJobText || '').trim();
  if (text.length < 20) return { restricted: false };

  const patterns = [
    { re: /\bin-country role\b/i, label: 'in-country role' },
    { re: new RegExp(`\\bbased in\\s+(${COUNTRY_NAMES})\\b`, 'i'), label: 'based in', capture: 1 },
    { re: new RegExp(`\\bbased out of\\s+(${COUNTRY_NAMES})\\b`, 'i'), label: 'based out of', capture: 1 },
    { re: new RegExp(`\\blocated in\\s+(${COUNTRY_NAMES})\\b`, 'i'), label: 'located in', capture: 1 },
    { re: new RegExp(`\\blocated within\\s+(${COUNTRY_NAMES})\\b`, 'i'), label: 'located within', capture: 1 },
    { re: new RegExp(`\\bmust be based in\\s+(${COUNTRY_NAMES})\\b`, 'i'), label: 'must be based in', capture: 1 },
    { re: new RegExp(`\\bmust be located in\\s+(${COUNTRY_NAMES})\\b`, 'i'), label: 'must be located in', capture: 1 },
    { re: new RegExp(`\\bmust reside in\\s+(${COUNTRY_NAMES})\\b`, 'i'), label: 'must reside in', capture: 1 },
    { re: new RegExp(`\\bremote within\\s+(${COUNTRY_NAMES})\\b`, 'i'), label: 'remote within', capture: 1 },
    { re: new RegExp(`\\banywhere in\\s+(${COUNTRY_NAMES})\\b`, 'i'), label: 'anywhere in', capture: 1 },
    {
      re: new RegExp(`\\bcan be executed from anywhere in\\s+(${COUNTRY_NAMES})\\b`, 'i'),
      label: 'can be executed from anywhere in',
      capture: 1,
    },
    { re: /\blocal candidates only\b/i, label: 'local candidates only' },
    { re: /\bresidents only\b/i, label: 'residents only' },
    {
      re: new RegExp(
        `\\bwork authorization\\s+(?:is\\s+)?(?:restricted|limited|required)\\s+(?:to\\s+)?(?:only\\s+)?(?:in\\s+)?(${COUNTRY_NAMES})\\b`,
        'i',
      ),
      label: 'work authorization restricted to',
      capture: 1,
    },
    {
      re: /\bwork authorization\s+(?:is\s+)?(?:restricted|limited)\s+to\s+one country\b/i,
      label: 'work authorization restricted to one country',
    },
  ];

  for (const pattern of patterns) {
    const match = text.match(pattern.re);
    if (!match || match.index == null) continue;
    if (isFalsePositiveRestrictionContext(text, match.index)) continue;

    let country = pattern.capture != null ? normalizeDetectedCountry(match[pattern.capture]) : '';
    if (!country && (pattern.label === 'in-country role' || pattern.label === 'local candidates only' || pattern.label === 'residents only')) {
      country = findCountryInText(text);
    }

    if (country && isBulgariaCountry(country)) continue;

    const snippet = match[0].trim();
    const evidence = country
      ? `${pattern.label} ${country} (${snippet})`
      : `${pattern.label} (${snippet})`;

    if (!country && (pattern.label === 'in-country role' || pattern.label === 'local candidates only' || pattern.label === 'residents only')) {
      const inferred = findCountryInText(text);
      if (inferred && !isBulgariaCountry(inferred)) {
        return { restricted: true, country: inferred, evidence: `${pattern.label}; ${evidence}` };
      }
      if (!inferred) continue;
    }

    if (!country && pattern.label.includes('work authorization')) {
      const inferred = findCountryInText(text);
      if (!inferred || isBulgariaCountry(inferred)) continue;
      country = inferred;
    }

    return { restricted: true, country: country || 'unspecified country', evidence };
  }

  return { restricted: false };
};

const applyFullJobTextLocationGuard = (ai, fullJobText) => {
  const guard = detectExplicitFullJobTextLocationRestriction(fullJobText);
  if (!guard.restricted) return { ai, guard };

  const out = { ...ai };
  out.location_fit = 'MISMATCH';
  out.apply = 'NO';
  out.final_decision = 'REJECT';

  const guardRisk = `Explicit location restriction in posting: ${guard.evidence}.`;
  const existingRisk = String(out.biggest_risk || '').trim();
  if (!existingRisk || !/explicit location restriction|based in|in-country role|must (?:be )?(?:located|reside)|remote within|anywhere in|local candidates only|residents only|work authorization/i.test(existingRisk)) {
    out.biggest_risk = guardRisk;
  } else if (!/explicit location restriction/i.test(existingRisk)) {
    out.biggest_risk = `${guardRisk} ${existingRisk}`;
  }

  return { ai: out, guard };
};

const clampInterviewProbability = (value) => {
  const n = Number(value);
  if (!Number.isFinite(n)) return 0;
  const pct = n >= 0 && n <= 10 ? Math.round(n * 10) : Math.round(n);
  return Math.max(0, Math.min(100, pct));
};

const normalizeRecommendation = (value, fallback = 'NO') => {
  const v = String(value || '').trim().toUpperCase();
  if (['YES', 'MONITOR', 'NO'].includes(v)) return v;
  return fallback;
};

const normalizeFinalDecision = (value, fallback = 'MONITOR') => {
  const v = String(value || '').trim().toUpperCase();
  if (v === 'APPLY IF INTERESTED' || v === 'APPLY_IF_INTERESTED') return 'MONITOR';
  if (v === 'APPLY NOW' || v === 'APPLY_NOW' || v === 'APPLY') return 'APPLY NOW';
  if (v === 'MONITOR') return 'MONITOR';
  if (v === 'REJECT') return 'REJECT';
  return fallback;
};

const normalizeGeoFit = (value, fallback = 'REVIEW_REQUIRED') => {
  const v = String(value || '').trim().toUpperCase();
  if (v === 'FULL MATCH' || v === 'FULL_MATCH') return 'FULL MATCH';
  if (v === 'REVIEW_REQUIRED') return 'REVIEW_REQUIRED';
  if (v === 'MISMATCH') return 'MISMATCH';
  return fallback;
};

const normalizePriority = (value, fallback = 'LOW') => {
  const v = String(value || '').trim().toUpperCase();
  if (['HIGH', 'MEDIUM', 'LOW'].includes(v)) return v;
  return fallback;
};

const normalizeSalaryConfidence = (value, fallback = 'LOW') => {
  const v = String(value || '').trim().toUpperCase();
  if (['HIGH', 'MEDIUM', 'LOW'].includes(v)) return v;
  return fallback;
};

const resolvePipelineStageFromVerified = (finalDecision, locationFit) => {
  const d = String(finalDecision || '').toUpperCase().trim();
  const lf = String(locationFit || '').toUpperCase().trim();

  if (lf === 'MISMATCH') return 'FINAL_REJECT_LOCATION';
  if (lf === 'REVIEW_REQUIRED') return 'REVIEW_REQUIRED';

  if (d === 'REJECT') return 'FINAL_REJECT';
  if ((d === 'APPLY NOW' || d === 'APPLY') && lf === 'FULL MATCH') return 'FINAL_ACCEPT';

  return 'FULL_EVALUATION';
};

const isLocationOnlySalaryAssumption = (value) => {
  const v = String(value || '').trim().toLowerCase();
  return [
    'remote bulgaria', 'remote europe', 'remote emea', 'remote worldwide', 'remote global',
    'bulgaria hybrid', 'bulgaria onsite', 'not specified',
  ].includes(v) || /^remote /.test(v);
};

const normalizeSalaryAssumption = (assumption) => {
  if (isLocationOnlySalaryAssumption(assumption)) {
    return 'Estimated from role seniority and executive compensation anchors';
  }
  const text = String(assumption || '').trim();
  return text || 'Not specified';
};

const parseSalaryNumber = (value) => {
  const s = String(value || '').trim();
  if (!s) return NaN;
  const kMatch = s.replace(/[,\s]/g, '').match(/^([\d.]+)k$/i);
  if (kMatch) return Math.round(parseFloat(kMatch[1]) * 1000);
  const digits = s.replace(/[^\d.]/g, '');
  const n = Number(digits);
  return Number.isFinite(n) ? Math.round(n) : NaN;
};

const mapSalaryFields = (ai) => {
  const rawRange = String(ai.salary_range_eur_gross || '').trim();
  const rawTarget = String(ai.salary_target_eur_gross || '').trim();
  let salaryRange = '';
  let salaryEstimate = '';

  const rangeMatch = rawRange.match(/([\d.k]+)\s*(?:-|–|—|\sto\s)+\s*([\d.k]+)/i);
  if (rangeMatch) {
    const low = parseSalaryNumber(rangeMatch[1]);
    const high = parseSalaryNumber(rangeMatch[2]);
    if (Number.isFinite(low) && Number.isFinite(high)) {
      const min = Math.min(low, high);
      const max = Math.max(low, high);
      salaryRange = min === max ? String(min) : `${min}-${max}`;
    }
  } else {
    const single = parseSalaryNumber(rawRange);
    if (Number.isFinite(single)) salaryRange = String(single);
  }

  const targetNum = parseSalaryNumber(rawTarget);
  if (Number.isFinite(targetNum)) {
    salaryEstimate = String(targetNum);
  } else if (salaryRange.includes('-')) {
    const [lowStr, highStr] = salaryRange.split('-');
    const low = Number(lowStr);
    const high = Number(highStr);
    if (Number.isFinite(low) && Number.isFinite(high)) {
      salaryEstimate = String(Math.round((low + high) / 2));
    }
  } else if (salaryRange) {
    salaryEstimate = salaryRange;
  }

  return {
    SalaryRange: salaryRange,
    SalaryEstimate: salaryEstimate,
    SalaryTarget: rawTarget || salaryEstimate,
  };
};

const sanitizeVerifiedLocation = (ai, location, workType, ctx) => {
  if (!isCountrySpecificRemote(location, workType)) return ai;
  const out = { ...ai };
  const hadLabelLocationReject = looksLikeLabelLocationRejection(
    out.biggest_risk,
    out.location_fit,
    out.final_decision,
    out.final_score,
  );

  out.location_fit = 'REVIEW_REQUIRED';

  if (hadLabelLocationReject || looksLikeLabelLocationRejection(out.biggest_risk, '', '', 0) || !String(out.biggest_risk || '').trim()) {
    out.biggest_risk = LOCATION_REVIEW_MSG;
  }

  if (hadLabelLocationReject) {
    const score = Number(out.final_score);
    const roleFloor = Math.max(
      Number(ctx.InitialEvalScore) || 0,
      Number(ctx.PreviewScore) || 0,
      7,
    );
    if (Number.isFinite(score) && score < 7) out.final_score = Math.max(score, roleFloor);
    if (String(out.apply || '').toUpperCase() === 'NO') out.apply = 'YES';
    if (String(out.final_decision || '').toUpperCase() === 'REJECT') {
      const s = Number(out.final_score);
      out.final_decision = s >= 8 ? 'APPLY NOW' : 'MONITOR';
    }
  }

  return out;
};

const raw =
  $json.output?.[0]?.content?.[0]?.text ||
  $json.output?.[0]?.text ||
  $json.content?.[0]?.text ||
  $json.text ||
  $json.response ||
  $json.message ||
  '';

let clean = String(raw)
  .replace(/```json/gi, '')
  .replace(/```/g, '')
  .trim();

const firstBrace = clean.indexOf('{');
const lastBrace = clean.lastIndexOf('}');

if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
  clean = clean.slice(firstBrace, lastBrace + 1);
}

let ai;

try {
  ai = JSON.parse(clean);
} catch (e) {
  return {
    json: {
      ...original,

      VerifiedScore: 0,
      VerifiedRecommendation: 'NO',
      FinalCV: '',
      VerifiedInterviewProbability: clampInterviewProbability(original.InterviewProbability),

      SalaryEstimate: '',
      SalaryTarget: '',
      SalaryConfidence: 'LOW',
      SalaryAssumption: 'Not specified',

      VerifiedRisk: 'Verified review returned invalid JSON.',
      VerifiedWhyApply: '',
      VerifiedPriority: original.Priority || 'LOW',

      SalaryRange: '',
      Location: original.Location || 'Not specified',
      LocationFit: original.LocationFit || 'REVIEW_REQUIRED',
      CountryFit: original.CountryFit || 'REVIEW_REQUIRED',

      FinalDecision: 'MONITOR',
      PipelineStage: 'FULL_EVALUATION',
      ParseError: e.message,

      DedupeKey: original.DedupeKey && original.DedupeKey !== '||'
        ? original.DedupeKey
        : (
            original.JobId ||
            `${original.Company || ''}|${original.Role || ''}|${original.Location || ''}`.toLowerCase()
          )
    }
  };
}

const evalLocation = ai.location || original.Location || '';
const evalWorkType = ai.work_type || original.WorkType || '';
const enrichmentFailed = String(original.EnrichmentStatus || '').toUpperCase() === 'FAILED';
if (!enrichmentFailed) {
  ai = sanitizeVerifiedLocation(ai, evalLocation, evalWorkType, original);
}

const { ai: locationGuardedAi, guard: fullJobTextLocationGuard } = applyFullJobTextLocationGuard(
  ai,
  original.FullJobText,
);
ai = locationGuardedAi;

const { ai: hardFitGuardedAi, guard: hardFitGuard } = fullJobTextLocationGuard.restricted
  ? { ai, guard: { hit: false } }
  : applyHardFitGuard(ai, original.FullJobText);
ai = hardFitGuardedAi;

const { ai: plgCalibratedAi } = fullJobTextLocationGuard.restricted || hardFitGuard.hit
  ? { ai }
  : applyPlgSpecializationCalibration(ai, original.FullJobText);
ai = plgCalibratedAi;

const countrySpecificRemote = isCountrySpecificRemote(evalLocation, evalWorkType);
const salaryFields = mapSalaryFields(ai);

const locationFit = fullJobTextLocationGuard.restricted
  ? 'MISMATCH'
  : normalizeGeoFit(ai.location_fit || original.LocationFit);
const countryFit = fullJobTextLocationGuard.restricted
  ? 'MISMATCH'
  : normalizeGeoFit(countrySpecificRemote ? 'REVIEW_REQUIRED' : (ai.country_fit || original.CountryFit));
const verifiedRecommendation = fullJobTextLocationGuard.restricted || hardFitGuard.hit
  ? 'NO'
  : normalizeRecommendation(ai.apply);
const finalDecision = fullJobTextLocationGuard.restricted || hardFitGuard.hit
  ? 'REJECT'
  : normalizeFinalDecision(ai.final_decision);
const pipelineStage = fullJobTextLocationGuard.restricted
  ? 'FINAL_REJECT_LOCATION'
  : hardFitGuard.hit
    ? 'FINAL_REJECT'
    : resolvePipelineStageFromVerified(finalDecision, locationFit);

return {
  json: {
    ...original,

    Role: original.Role || ai.role || '',
    Company: original.Company || ai.company || '',
    JobId: original.JobId || ai.job_id || '',
    WorkType: original.WorkType || ai.work_type || '',
    URL: original.URL || ai.url || '',

    VerifiedScore: ai.final_score ?? 0,
    VerifiedRecommendation: verifiedRecommendation,
    FinalCV: ai.best_cv || 'Strategy & Operations CV',
    VerifiedInterviewProbability: clampInterviewProbability(ai.interview_probability ?? original.InterviewProbability),

    SalaryEstimate: salaryFields.SalaryEstimate,
    SalaryTarget: salaryFields.SalaryTarget,
    SalaryConfidence: normalizeSalaryConfidence(ai.salary_confidence),
    SalaryAssumption: normalizeSalaryAssumption(ai.salary_assumption),

    VerifiedRisk: (() => {
      let risk = ai.biggest_risk || '';
      if (enrichmentFailed && !/enrichment|extract|full job|posting/i.test(risk)) {
        const err = original.EnrichmentError || 'LinkedIn job description could not be extracted.';
        risk = risk ? `${risk} | Enrichment failed: ${err}` : `Enrichment failed: ${err}`;
      }
      return risk;
    })(),
    VerifiedWhyApply: ai.why_apply || '',
    VerifiedPriority: normalizePriority(ai.follow_up_priority || original.Priority),

    SalaryRange: salaryFields.SalaryRange,
    Location: ai.location || original.Location || 'Not specified',
    LocationFit: locationFit,
    CountryFit: countryFit,

    FinalDecision: finalDecision,
    PipelineStage: pipelineStage,

    FullJobText: original.FullJobText || '',
    FullJobTextLength: original.FullJobTextLength ?? 0,
    EnrichmentStatus: original.EnrichmentStatus || '',
    EnrichmentError: original.EnrichmentError || '',

    ParseError: '',

    DedupeKey: original.DedupeKey && original.DedupeKey !== '||'
      ? original.DedupeKey
      : (
          ai.dedupe_key ||
          ai.job_id ||
          original.JobId ||
          `${original.Company || ai.company || ''}|${original.Role || ai.role || ''}|${ai.location || original.Location || ''}`.toLowerCase()
        )
  }
};

const MIN_FULL_JOB_TEXT = 200;
const MAX_FULL_JOB_TEXT = 15000;

const decodeHtml = (s) =>
  String(s || "")
    .replace(/&nbsp;/gi, " ")
    .replace(/&amp;/gi, "&")
    .replace(/&quot;/gi, '"')
    .replace(/&#39;/gi, "'")
    .replace(/&lt;/gi, "<")
    .replace(/&gt;/gi, ">");

const stripTags = (html) =>
  String(html || "")
    .replace(/<script[\s\S]*?<\/script>/gi, " ")
    .replace(/<style[\s\S]*?<\/style>/gi, " ")
    .replace(/<!--[\s\S]*?-->/g, " ")
    .replace(/<[^>]+>/g, " ")
    .replace(/\s+/g, " ")
    .trim();

const isJobPostingType = (value) => {
  if (value === "JobPosting") return true;
  if (Array.isArray(value)) return value.includes("JobPosting");
  return false;
};

const extractJsonLdJobPostingDescription = (html) => {
  const blocks =
    String(html || "").match(
      /<script[^>]*type=["']application\/ld\+json["'][^>]*>([\s\S]*?)<\/script>/gi,
    ) || [];

  for (const block of blocks) {
    const inner = block.replace(/^<script[^>]*>/i, "").replace(/<\/script>$/i, "").trim();
    try {
      const parsed = JSON.parse(inner);
      const nodes = Array.isArray(parsed) ? parsed : [parsed];
      for (const node of nodes) {
        const graph = Array.isArray(node?.["@graph"]) ? node["@graph"] : [];
        const candidates = [node, ...graph];
        for (const item of candidates) {
          if (!isJobPostingType(item?.["@type"])) continue;
          const desc = item?.description;
          if (desc && String(desc).trim().length > 80) {
            return decodeHtml(stripTags(String(desc)));
          }
        }
      }
    } catch {
      // try next block
    }
  }
  return "";
};

const extractShowMoreMarkup = (html) => {
  const raw = String(html || "");
  const patterns = [
    /class="[^"]*show-more-less-html__markup[^"]*"[^>]*>([\s\S]*?)<\/div>/i,
    /show-more-less-html__markup[^>]*>([\s\S]*?)<\/div>/i,
  ];
  for (const pattern of patterns) {
    const match = raw.match(pattern);
    if (match?.[1]) {
      const text = decodeHtml(stripTags(match[1]));
      if (text.length >= MIN_FULL_JOB_TEXT) return text;
    }
  }
  return "";
};

const extractGuestDescriptionRich = (html) => {
  const raw = String(html || "");
  const patterns = [
    /class="[^"]*description__text[^"]*description__text--rich[^"]*"[^>]*>([\s\S]*?)<\/div>/i,
    /description__text--rich[^>]*>([\s\S]*?)<\/div>/i,
  ];
  for (const pattern of patterns) {
    const match = raw.match(pattern);
    if (match?.[1]) {
      const text = decodeHtml(stripTags(match[1]));
      if (text.length >= MIN_FULL_JOB_TEXT) return text;
    }
  }
  return "";
};

const extractLinkedInDescription = (html) => {
  const jsonLd = extractJsonLdJobPostingDescription(html);
  if (jsonLd.length >= MIN_FULL_JOB_TEXT) return jsonLd;

  const showMore = extractShowMoreMarkup(html);
  if (showMore.length >= MIN_FULL_JOB_TEXT) return showMore;

  const guestRich = extractGuestDescriptionRich(html);
  if (guestRich.length >= MIN_FULL_JOB_TEXT) return guestRich;

  return decodeHtml(stripTags(html));
};

const looksLikeHardBlock = (html, text) => {
  const h = String(html || "").toLowerCase();
  const t = String(text || "").toLowerCase();
  if (h.includes("authwall")) return true;
  if (t.includes("sign in to linkedin")) return true;
  if (t.length < 80 && /login|authwall/.test(h)) return true;
  return false;
};

const upstream = $("Normalize AI Evaluation").item?.json || {};
const jobId = String(upstream.JobId || $json.JobId || "").trim();
const statusCode = Number($json.statusCode || 0);
const html =
  typeof $json.data === "string"
    ? $json.data
    : typeof $json.body === "string"
      ? $json.body
      : typeof $json === "string"
        ? $json
        : "";

let enrichmentError = "";
let fullJobText = "";

if (!jobId && !String(upstream.URL || $json.URL || "").trim()) {
  enrichmentError = "Missing JobId and URL";
} else if (statusCode >= 400) {
  enrichmentError = `HTTP ${statusCode}`;
} else if (!String(html).trim()) {
  enrichmentError = "Empty response";
} else {
  fullJobText = extractLinkedInDescription(html).slice(0, MAX_FULL_JOB_TEXT);
  const stripped = stripTags(html);
  if (fullJobText.trim().length < MIN_FULL_JOB_TEXT) {
    enrichmentError = looksLikeHardBlock(html, stripped)
      ? "Auth wall / login page"
      : "No description block found";
  }
}

const enrichmentStatus =
  fullJobText.trim().length >= MIN_FULL_JOB_TEXT && !enrichmentError ? "OK" : "FAILED";

return {
  json: {
    ...upstream,
    FullJobText: fullJobText.trim(),
    FullJobTextLength: fullJobText.trim().length,
    EnrichmentStatus: enrichmentStatus,
    EnrichmentError: enrichmentStatus === "OK" ? "" : enrichmentError || "Extraction failed",
  },
};
